using System;using System.IO;using System.Linq;class Example{static Brush.Point P(double x,double y)=>new(x,y);static void Main(string[]args){var raw=new(double,double)[]{(500,520),(450,450),(390,395),(320,370),(250,370),(180,390),(130,450),(120,520),(155,585),(220,635),(300,650),(380,620),(440,570),(500,520),(560,465),(620,410),(700,370),(770,380),(830,420),(870,480),(875,545),(845,610),(790,660),(720,675),(650,655),(585,610),(540,560),(500,520)};var points=raw.Select(v=>P(v.Item1,v.Item2)).ToList();if(Brush.BuildRoundedDrawingPath(new[]{P(0,0),P(100,0),P(100,100)},40)!="M 0 0 L 55 0 Q 100 0 100 45 L 100 100")throw new Exception("check");var input=args.Length>0?args[0]:"assets/example.webp";var output=args.Length>1?args[1]:"generated/csharp.svg";var svg=Brush.RenderSvg(File.ReadAllBytes(input),"image/webp",1000,1000,points,"🤝 best friends forever",new Brush.Options{MagicGradient=true});Directory.CreateDirectory(Path.GetDirectoryName(output)!);File.WriteAllText(output,svg);Console.WriteLine($"Wrote {output}");}}
